     1	import { useMemo, useState } from 'react';
     2	import { Link, useNavigate } from 'react-router-dom';
     3	import { useModelIndex, useModelStore, useModelDelete, useAuth } from '@rhino-dev/rhino-react';
     4	import type { Blog } from '../types';
     5	import { Icon } from '../components/Icons';
     6	import { useToast } from '../components/Toaster';
     7	import { fmtRelative } from '../lib/format';
     8	import { Loading } from './DashboardPage';
     9	
    10	const PER_PAGE = 10;
    11	type Sort = '-id' | 'title' | '-title' | 'created_at' | '-created_at';
    12	
    13	export function BlogsPage() {
    14	  const nav = useNavigate();
    15	  const toast = useToast();
    16	  const { user } = useAuth();
    17	  const [search, setSearch] = useState('');
    18	  const [publishedFilter, setPublishedFilter] = useState('');
    19	  const [sort, setSort] = useState<Sort>('-created_at');
    20	  const [page, setPage] = useState(1);
    21	  const [showNew, setShowNew] = useState(false);
    22	
    23	  const filters = useMemo(() => {
    24	    const f: Record<string, any> = {};
    25	    if (publishedFilter === 'true') f.published = true;
    26	    if (publishedFilter === 'false') f.published = false;
    27	    return f;
    28	  }, [publishedFilter]);
    29	
    30	  const blogs = useModelIndex<Blog>('blogs', {
    31	    filters,
    32	    search: search || undefined,
    33	    sort,
    34	    page,
    35	    perPage: PER_PAGE,
    36	  });
    37	
    38	  const store = useModelStore<Blog>('blogs');
    39	  const del = useModelDelete<Blog>('blogs');
    40	
    41	  const list = blogs.data?.data ?? [];
    42	  const pag = blogs.data?.pagination;
    43	
    44	  function onSortClick(field: Exclude<Sort, `-${string}`>) {
    45	    setSort(s => (s === field ? (`-${field}` as Sort) : field));
    46	  }
    47	
    48	  return (
    49	    <>
    50	      <div className="page-head">
    51	        <div>
    52	          <h1 className="page-title">Blogs</h1>
    53	          <p className="page-sub">Multi-tenant scope: <span className="mono accent">/api/{`{org}`}/blogs</span></p>
    54	        </div>
    55	        <button className="btn btn-primary" onClick={() => setShowNew(true)}>
    56	          <Icon.plus size={14} /> New blog
    57	        </button>
    58	      </div>
    59	
    60	      <div className="toolbar">
    61	        <input
    62	          className="input input-search"
    63	          style={{ flex: 1, maxWidth: 320 }}
    64	          placeholder="Search title / body…"
    65	          value={search}
    66	          onChange={e => { setPage(1); setSearch(e.target.value); }}
    67	        />
    68	        <select
    69	          className="input select"
    70	          value={publishedFilter}
    71	          onChange={e => { setPage(1); setPublishedFilter(e.target.value); }}
    72	        >
    73	          <option value="">All status</option>
    74	          <option value="true">Published</option>
    75	          <option value="false">Draft</option>
    76	        </select>
    77	        <span className="faint" style={{ marginLeft: 'auto', fontSize: 12 }}>
    78	          {blogs.isFetching ? 'fetching…' : `${list.length} of ${pag?.total ?? list.length}`}
    79	        </span>
    80	      </div>
    81	
    82	      <div className="card" style={{ overflow: 'visible' }}>
    83	        {blogs.isLoading ? <Loading /> : list.length === 0 ? (
    84	          <div className="empty">
    85	            <h3>No blogs match</h3>
    86	            <p>Try a different filter, or create one.</p>
    87	          </div>
    88	        ) : (
    89	          <table className="table">
    90	            <thead>
    91	              <tr>
    92	                <Th label="Title" field="title" sort={sort} onClick={onSortClick} />
    93	                <th>Status</th>
    94	                <Th label="Created" field="created_at" sort={sort} onClick={onSortClick} />
    95	                <th style={{ width: 60 }}></th>
    96	              </tr>
    97	            </thead>
    98	            <tbody>
    99	              {list.map(b => (
   100	                <tr key={b.id} onClick={() => nav(`/blogs/${b.id}`)}>
   101	                  <td>
   102	                    <Link to={`/blogs/${b.id}`} onClick={e => e.stopPropagation()} style={{ fontWeight: 600 }}>
   103	                      {b.title || 'Untitled'}
   104	                    </Link>
   105	                    <div className="faint" style={{ fontSize: 11, marginTop: 2 }}>
   106	                      {b.body?.slice(0, 90)}
   107	                      {b.body && b.body.length > 90 ? '...' : ''}
   108	                    </div>
   109	                  </td>
   110	                  <td>
   111	                    <span className={`pill ${b.published ? 'pill-active' : 'pill-draft'}`}>
   112	                      {b.published ? 'Published' : 'Draft'}
   113	                    </span>
   114	                  </td>
   115	                  <td className="faint">{fmtRelative(b.created_at)}</td>
   116	                  <td>
   117	                    <button
   118	                      className="btn btn-ghost btn-icon"
   119	                      title="Soft delete (move to trash)"
   120	                      onClick={async e => {
   121	                        e.stopPropagation();
   122	                        if (!confirm(`Delete blog "${b.title || 'Untitled'}"?`)) return;
   123	                        try {
   124	                          await del.mutateAsync(b.id);
   125	                          toast(`Deleted "${b.title || 'Untitled'}"`, 'ok');
   126	                        } catch (err) {
   127	                          toast(`Delete failed: ${(err as Error).message}`, 'error');
   128	                        }
   129	                      }}
   130	                    >
   131	                      <Icon.trash size={14} />
   132	                    </button>
   133	                  </td>
   134	                </tr>
   135	              ))}
   136	            </tbody>
   137	          </table>
   138	        )}
   139	
   140	        {pag && pag.lastPage > 1 && (
   141	          <div className="pager">
   142	            <div className="pager-info">Page {pag.currentPage} of {pag.lastPage} · {pag.total} total</div>
   143	            <div className="pager-ctrls">
   144	              <button className="btn btn-sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>
   145	                <Icon.arrowL size={12} />
   146	              </button>
   147	              <button className="btn btn-sm" disabled={page >= pag.lastPage} onClick={() => setPage(p => p + 1)}>
   148	                <Icon.arrowR size={12} />
   149	              </button>
   150	            </div>
   151	          </div>
   152	        )}
   153	      </div>
   154	
   155	      {showNew && (
   156	        <NewBlogModal
   157	          onClose={() => setShowNew(false)}
   158	          onCreate={async data => {
   159	            try {
   160	              const created = await store.mutateAsync(data);
   161	              toast(`Created "${created.title || 'Untitled'}"`, 'ok');
   162	              setShowNew(false);
   163	            } catch (err) {
   164	              toast(`Create failed: ${(err as Error).message}`, 'error');
   165	            }
   166	          }}
   167	          busy={store.isPending}
   168	        />
   169	      )}
   170	    </>
   171	  );
   172	}
   173	
   174	function Th(props: { label: string; field: string | null; sort?: string; onClick?: (f: any) => void }) {
   175	  const { label, field, sort, onClick } = props;
   176	  if (!field || !onClick) return <th>{label}</th>;
   177	  const active = sort === field || sort === `-${field}`;
   178	  return (
   179	    <th className={active ? 'sorted' : ''} onClick={() => onClick(field)}>
   180	      {label}
   181	      <span className="sort-arrow">{active ? (sort === field ? '↑' : '↓') : '↕'}</span>
   182	    </th>
   183	  );
   184	}
   185	
   186	function NewBlogModal({ onClose, onCreate, busy }: { onClose: () => void; onCreate: (data: Partial<Blog>) => Promise<void>; busy: boolean }) {
   187	  const [title, setTitle] = useState('');
   188	  const [body, setBody] = useState('');
   189	  const [published, setPublished] = useState(false);
   190	
   191	  return (
   192	    <div className="modal-backdrop" onClick={onClose}>
   193	      <div className="modal" onClick={e => e.stopPropagation()}>
   194	        <div className="modal-head">
   195	          <div className="modal-title">New blog</div>
   196	          <button className="btn btn-ghost btn-icon" onClick={onClose}><Icon.close /></button>
   197	        </div>
   198	        <div className="modal-body">
   199	          <form className="form" onSubmit={e => { e.preventDefault(); onCreate({ title, body, published }); }}>
   200	            <div className="field">
   201	              <label>Title</label>
   202	              <input className="input" value={title} onChange={e => setTitle(e.target.value)} required autoFocus />
   203	            </div>
   204	            <div className="field">
   205	              <label>Body</label>
   206	              <textarea className="input" rows={6} value={body} onChange={e => setBody(e.target.value)} required />
   207	            </div>
   208	            <div className="field-row" style={{ display: 'flex', alignItems: 'center', gap: 8, margin: '12px 0' }}>
   209	              <input
   210	                type="checkbox"
   211	                id="published"
   212	                checked={published}
   213	                onChange={e => setPublished(e.target.checked)}
   214	              />
   215	              <label htmlFor="published" style={{ margin: 0, cursor: 'pointer' }}>Publish immediately</label>
   216	            </div>
   217	            <div className="modal-foot" style={{ padding: 0, border: 0 }}>
   218	              <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
   219	              <button type="submit" className="btn btn-primary" disabled={busy}>
   220	                {busy ? <span className="spinner" /> : <Icon.check size={14} />} Create
   221	              </button>
   222	            </div>
   223	          </form>
   224	        </div>
   225	      </div>
   226	    </div>
   227	  );
   228	}
